 @import "tailwindcss";
 @plugin "@tailwindcss/typography";

 @theme {
   --font-sans: "Inter", ui-sans-serif, system-ui, sans-serif;
   --font-mono: "JetBrains Mono", ui-monospace, "Cascadia Code", "Fira Code", monospace;

   --color-accent: #38bdf8;
   --color-accent-dim: #0ea5e9;
   --color-accent-soft: rgba(56, 189, 248, 0.15);
   --color-accent-glow: rgba(56, 189, 248, 0.45);

   --color-surface: #050507;
   --color-surface-alt: #0c0d10;
   --color-surface-elevated: #131418;
   --color-surface-raised: #191b21;

   --color-border: #1f2127;
   --color-border-subtle: #14161b;
   --color-border-bright: #2a2d35;

   --color-text: #ededf0;
   --color-text-muted: #8b8d96;
   --color-text-dim: #4d4f57;
   --color-text-faint: #2e3038;

   --shadow-glow-sm: 0 0 20px -5px var(--color-accent-glow);
   --shadow-glow: 0 0 40px -8px var(--color-accent-glow);
   --shadow-elevated: 0 1px 0 0 rgba(255,255,255,0.04) inset, 0 20px 40px -20px rgba(0,0,0,0.8);
 }

 @layer base {
   :root {
     color-scheme: dark;
   }

   html {
     scroll-behavior: smooth;
   }

   body {
     background-color: var(--color-surface);
     color: var(--color-text);
     font-family: var(--font-sans);
     font-feature-settings: "ss01", "cv11";
     -webkit-font-smoothing: antialiased;
     -moz-osx-font-smoothing: grayscale;
     background-image:
       radial-gradient(ellipse 70% 40% at 50% -20%, rgba(56, 189, 248, 0.04), transparent 70%),
       linear-gradient(to bottom, var(--color-surface), #030305 60%);
     background-attachment: fixed;
     position: relative;
     overflow-x: hidden;
   }

   body::before {
     content: "";
     position: fixed;
     inset: 0;
     background-image:
       linear-gradient(var(--color-border-subtle) 1px, transparent 1px),
       linear-gradient(90deg, var(--color-border-subtle) 1px, transparent 1px);
     background-size: 56px 56px;
     background-position: -1px -1px;
     mask-image: radial-gradient(ellipse 70% 60% at 50% 30%, #000 30%, transparent 75%);
     -webkit-mask-image: radial-gradient(ellipse 70% 60% at 50% 30%, #000 30%, transparent 75%);
     pointer-events: none;
     z-index: 0;
     opacity: 0.6;
   }

   body > * {
     position: relative;
     z-index: 1;
   }

   ::selection {
     background-color: var(--color-accent);
     color: var(--color-surface);
     text-shadow: none;
   }

   a {
     color: var(--color-accent);
     text-decoration: none;
     transition: color 0.15s ease, text-shadow 0.15s ease;
   }

   a:hover {
     color: #7dd3fc;
   }

   code {
     font-family: var(--font-mono);
   }

   h1, h2, h3, h4, h5, h6 {
     font-family: var(--font-sans);
     font-weight: 600;
     letter-spacing: -0.025em;
     color: var(--color-text);
   }
 }

 @layer components {
   .prose {
     --tw-prose-body: var(--color-text-muted);
     --tw-prose-headings: var(--color-text);
     --tw-prose-links: var(--color-accent);
     --tw-prose-code: var(--color-accent);
     --tw-prose-pre-bg: var(--color-surface-alt);
     --tw-prose-pre-code: var(--color-text);
     --tw-prose-bold: var(--color-text);
     --tw-prose-quotes: var(--color-text-muted);
     --tw-prose-quote-borders: var(--color-accent);
     --tw-prose-counters: var(--color-text-dim);
     --tw-prose-bullets: var(--color-text-faint);
     --tw-prose-hr: var(--color-border);
     --tw-prose-th-borders: var(--color-border);
     --tw-prose-td-borders: var(--color-border-subtle);
   }

   .prose pre {
     border: none;
     border-radius: 4px;
     box-shadow: 0 1px 0 0 rgba(255,255,255,0.04) inset;
     position: relative;
   }

   .prose pre::before {
     content: "";
     position: absolute;
     inset: 0 0 auto 0;
     height: 1px;
     background: linear-gradient(90deg, transparent, var(--color-accent-glow) 50%, transparent);
     opacity: 0.6;
   }

   .prose code::before,
   .prose code::after {
     content: none;
   }

   .prose code {
     font-weight: 400;
     font-size: 0.875em;
     background: var(--color-accent-soft);
     padding: 0.1rem 0.3rem;
     border-radius: 3px;
   }

   .prose img {
     border-radius: 4px;
     border: 1px solid var(--color-border-subtle);
   }

   .copy-button {
     position: absolute;
     top: 0.5rem;
     right: 0.5rem;
     padding: 0.25rem 0.5rem;
     font-size: 0.75rem;
     font-family: var(--font-mono);
     background: var(--color-surface-elevated);
     color: var(--color-text-muted);
     border: 1px solid var(--color-border);
     border-radius: 3px;
     cursor: pointer;
     opacity: 0;
     transition: opacity 0.15s ease, color 0.15s ease, border-color 0.15s ease;
   }

   .prose pre:hover .copy-button,
   .prose pre:focus-within .copy-button {
     opacity: 1;
   }

   .copy-button:hover {
     color: var(--color-accent);
     border-color: var(--color-accent);
     box-shadow: var(--shadow-glow-sm);
   }

   .tag {
     display: inline-flex;
     align-items: center;
     padding: 0.125rem 0.55rem;
     font-size: 0.7rem;
     font-family: var(--font-mono);
     letter-spacing: 0.02em;
     background: var(--color-surface-elevated);
     color: var(--color-text-muted);
     border-radius: 3px;
     border: 1px solid transparent;
     transition: color 0.15s ease, background 0.15s ease, box-shadow 0.15s ease;
   }

   .tag:hover {
     color: var(--color-accent);
     background: var(--color-surface-raised);
   }

   .section-heading {
     display: flex;
     align-items: center;
     gap: 0.75rem;
     margin-bottom: 1.5rem;
   }

   .section-heading::before {
     content: "//";
     font-family: var(--font-mono);
     color: var(--color-text-dim);
     font-size: 0.75rem;
   }

   .section-heading::after {
     content: "";
     flex: 1;
     height: 1px;
     background: linear-gradient(90deg, var(--color-border-bright), transparent);
   }

   .card {
     position: relative;
     background: var(--color-surface-elevated);
     border-radius: 4px;
     box-shadow: 0 1px 0 0 rgba(255,255,255,0.03) inset;
     transition: background 0.2s ease;
   }

   .card::before {
     content: "";
     position: absolute;
     inset: 0 0 auto 0;
     height: 1px;
     background: var(--color-border-bright);
     opacity: 0.5;
     transition: opacity 0.2s ease, background 0.2s ease;
   }

   .card:hover {
     background: var(--color-surface-raised);
   }

   .card:hover::before {
     background: var(--color-accent);
     opacity: 0.6;
   }

   .term-label {
     font-family: var(--font-mono);
     color: var(--color-accent);
     font-size: 0.75rem;
     letter-spacing: 0.05em;
   }

   .term-label::before {
     content: "$ ";
     opacity: 0.6;
   }

   .cursor::after {
     content: "▊";
     display: inline-block;
     margin-left: 0.25rem;
     color: var(--color-accent);
     animation: blink 1.1s steps(2, start) infinite;
     transform: translateY(-2px);
   }

   @keyframes blink {
     to { opacity: 0; }
   }

