   --color-text-dim: #4d4f57;
   --color-text-faint: #2e3038;

   --shadow-glow-sm: 0 0 20px -5px var(--color-accent-glow);
   --shadow-glow: 0 0 40px -8px var(--color-accent-glow);
   --shadow-elevated: 0 1px 0 0 rgba(255,255,255,0.04) inset, 0 20px 40px -20px rgba(0,0,0,0.8);
 }

 @layer base {
   :root {
     color-scheme: dark;
   }

   html {
     scroll-behavior: smooth;
   }

   body {
     background-color: var(--color-surface);
     color: var(--color-text);
     font-family: var(--font-sans);
     font-feature-settings: "ss01", "cv11";
     -webkit-font-smoothing: antialiased;
     -moz-osx-font-smoothing: grayscale;
